/**
 * Leospring直播源 - 修复版
 * 移除对 cat.js 的依赖，使用原生 JS
 */

let siteUrl = 'http://api.hclyz.com:81/mf/';
let siteKey = '';
let siteType = 0;
let cateList = {};

async function request(reqUrl, postData, post) {
    let res = await req(reqUrl, {
        method: post ? 'post' : 'get',
        data: postData || {},
        postType: post ? 'form' : '',
    });
    return res.content;
}

async function init(cfg) {
    siteKey = cfg.skey;
    siteType = cfg.stype;
    if (cfg.ext) siteUrl = cfg.ext;
    try {
        let txt = await request(siteUrl + 'json.txt');
        cateList = JSON.parse(txt);
    } catch(e) {
        console.log('init error:', e);
        cateList = {};
    }
}

async function home(filter) {
    let classes = [];
    for (let key in cateList) {
        classes.push({ type_id: key, type_name: key });
    }
    return JSON.stringify({ class: classes });
}

async function category(tid, pg, filter, ext) {
    let items = cateList[tid] || [];
    let videos = items.map(item => ({
        vod_id: item.address,
        vod_name: item.title,
        vod_pic: (item.xinimg || '').replace("http://cdn.gcufbd.top/img/", "https://github.moeyy.xyz/https://raw.githubusercontent.com/fish2018/lib/refs/heads/main/imgs/"),
        vod_remarks: item.Number || ''
    }));
    return JSON.stringify({
        list: videos,
        page: pg,
        pagecount: 1,
        total: videos.length
    });
}

async function detail(id) {
    try {
        let url = siteUrl + id;
        let resp = await request(url);
        let data = JSON.parse(resp);
        let zhubo = data.zhubo;
        if (!zhubo || !zhubo.length) throw new Error('zhubo字段为空');
        let playUrls = zhubo.map(vod => vod.title + '$' + vod.address).join('#');
        let video = {
            vod_play_from: 'Leospring',
            vod_play_url: playUrls,
            vod_content: 'github.com/fish2018'
        };
        return JSON.stringify({ list: [video] });
    } catch (e) {
        console.log('detail error:', e, 'id=', id);
        return JSON.stringify({ list: [] });
    }
}

async function play(flag, id, flags) {
    return JSON.stringify({ parse: 0, url: id });
}

export function __jsEvalReturn() {
    return { init, home, category, detail, play };
}
